actionSource.STSource:
(* initialisation of packaging robot *)

if Start_process 
	then
	Robot_one.robot_running:=true;
	else 
	Robot_one.robot_running:=false;
end_if;

(* resetting last step *)

If Start_Robot.x 
	then
	reset (Robot_one.material_down_done);
end_if;

(* rotation left after initialisation *)

if Robot_one.robot_running and re (Belt_running) 
	then
	set (Robot_one.Rotation_left);	
end_if;

if robot_one.robot_running and not Robot_one.Rotation_left and rotation.t >= t#300ms 
	then
	set   (Robot_one.init);
	else 
	reset (Robot_one.init);
end_if;

(* delay time for left rotation *)

Robot_rotation (IN := Robot_one.Rotation_left,
  PT := t#1s,
  Q => Robot_one.cvRobot_one);

(* rotation left done *)

if Robot_one.cvRobot_one 
	then
	set (Robot_one.Rotation_left_done);
	reset (Robot_one.Rotation_left);
	else 
	reset (Robot_one.Rotation_left_done);
end_if;

(* packaging *)

if     Robot_one.rotation_right_five_done 
   or  Robot_one.rotation_right_ten_done 
   and Packaging.t>t#200ms 
	then
	set (Robot_one.arm_right);
end_if;

(* delay time for rotation right *)

Arm_right_Timer (IN := robot_one.arm_right,
  		 PT := t#1s,
  		  Q => robot_one.cv_arm_right);

(* material down in box *)

if robot_one.cv_arm_right 
	then
	reset (Material_picked_off);
	set   (Robot_one.material_down);
	reset (Robot_one.rotation_right_five_done);
	reset (Robot_one.rotation_right_ten_done);
	set   (Robot_one.cv_material_down_done);
	reset (Robot_one.arm_right);
end_if;

(* delay time for material down in box *)

Material_down_Timer (IN := Robot_one.material_down,
  		     PT := t#1s,
		      Q => Robot_one.cv_material_down_done);

(* material down done *)

if Robot_one.cv_material_down_done 
	then
	reset (Robot_one.material_down);
	set   (Robot_one.material_down_done);
end_if;

(* movement of arm one if rotation left done *)

if     Robot_one.Rotation_left_done 
   and Arm_1.t>t#100ms 
	then
	set (Robot_one.Arm_one);	
end_if;

(* delay time for movement arm one *)

Arm_1_Timer (IN := Robot_one.Arm_one,
	     PT := t#1s,
	      Q => Robot_one.cvArm_one);

(* movement arm one doen *)

if Robot_one.cvArm_one 
	then
	set   (Robot_one.Arm_one_done);
	reset (Robot_one.Arm_one);
	reset (robot_one.cvArm_one);
	reset (Robot_one.Rotation_left_done);
	else 
	reset (Robot_one.Arm_one_done);
end_if;

(* movement of arm two if movement arm one done *)

if Robot_one.Arm_one_done and arm_2.t>t#100ms 
	then
	set (Robot_one.Arm_two);	
end_if;

(* delay time for movement arm two *)

Arm_2_Timer (IN := Robot_one.Arm_two,
	     PT := t#1s,
	      Q => Robot_one.cvArm_two);

(* movement arm two done *)

if Robot_one.cvArm_two 
	then
	set   (Robot_one.Arm_two_done);
	reset (Robot_one.Arm_two);
	reset (Robot_one.cvArm_two);
	reset (Robot_one.Arm_one_done);
	else 
	reset (Robot_one.Arm_two_done);
end_if;

(* decide between step five and step ten *)

if Robot_one.Arm_two_done and five_pices 
	then
	set   (Robot_one.packaging_5);
	reset (Robot_one.packaging_10);
	else 
	reset (Robot_one.packaging_5);
end_if;

If Robot_one.Arm_two_done and ten_pices 
	then
	reset (Robot_one.packaging_5);
	set   (Robot_one.packaging_10);
	else 
	reset (Robot_one.packaging_10);
end_if;

(* if five coosen initialisation fo step five *)

if Robot_one.Arm_two_done and five.t>t#200ms then
	set (Robot_one.Taking_Material);
	set (Material_picked_off);
end_if;

(* delay time for taking material *)

PACKAGING_TIMER (IN := Robot_one.Taking_Material,
       		 PT := t#1s,
       		  Q => hb_Packaging);

(* movement arm two done rotating right to packageing *)

if hb_Packaging 
	then
	reset (Robot_one.Arm_two_done);
	set   (Robot_one.Rotation_right_five);
	reset (Robot_one.Taking_Material);

end_if;

(* delay time for rotation right *) 

ROTATION_RIGHT_TIMER   (IN := Robot_one.Rotation_right_five,
			PT := t#1s,
			Q => hb_rotation_right);

(* rotation right done *)

if hb_rotation_right 
	then
	set   (Robot_one.rotation_right_five_done);
	reset (Robot_one.Rotation_right_five);
end_if;

(* if ten coosen initialisation fo step five *)

if Robot_one.Arm_two_done and ten.t>t#200ms 
	then
	set (Robot_one.Taking_Material);
	set (Material_picked_off);
end_if;

(* delay time for taking material *)

PACKAGING_TIMER (IN := Robot_one.Taking_Material,
       		 PT := t#1s,
       		  Q => hb_Packaging);

(* movement arm two done rotating right to packageing *)

if hb_Packaging 
	then
	reset (Robot_one.Arm_two_done);
	set   (Robot_one.Rotation_right_ten);
	reset (Robot_one.Taking_Material);

end_if;

(* delay time for rotation right *)

ROTATION_RIGHT_TIMER (IN := Robot_one.Rotation_right_ten,
		      PT := t#1s,
		       Q => hb_rotation_right);

(* rotation right done *)

if hb_rotation_right 
	then
	set   (Robot_one.rotation_right_ten_done);
	reset (Robot_one.Rotation_right_ten);
end_if;
